INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('1af703c0-7373-5bbd-ba90-dc0b36eceef9', 'e2bae4a4-4742-48a0-b778-64f45bd4b3c7', 'Although the movie trailer looked exciting, the ___ plot was quite boring and predictable.', '雖然電影預告片看起來很刺激，但實際的情節卻相當無聊且容易預測。', 'actual', 'sudden', 'recent', 'various', 'root: act (做/行動) + ual (形容詞字尾) → 實際的、事實上的', '想著 ''action'' 是行動，action 之後發生的就是 ''actual'' 實際發生的事情。', '2026-07-06 17:27:08', '2026-07-06 17:27:08'),
('2af6a1b9-499d-55f7-afdf-ae37a21126a1', '69e96f33-3911-4d98-b9bb-d81856018f41', 'It was ___ midnight when the loud noise woke me up.', '當巨大的噪音吵醒我時，已經___半夜了。', 'almost', 'softly', 'calmly', 'purely', '由 all (全部) 與 most (大部分) 的概念結合而成。', 'all + most → 接近全部 → almost (幾乎)。', '2026-07-06 20:09:12', '2026-07-06 20:09:12'),
('0e174e3e-0444-5e28-b79f-13b7a84cd629', 'b199cd44-bbd9-451d-a11f-d8b8c62dcfb8', 'Please listen carefully to the school''s ___ regarding the changes to the exam schedule.', '請仔細聽取學校關於考試時間表變動的公告。', 'announcement', 'compliment', 'punishment', 'achievement', 'ann (向/對) + nounce (說/報告) + ment (名詞字尾) → 表示向大眾傳達訊息，即公告。', 'an (向) + nounce (說) + ment (名詞) → 向大家說出的訊息 → 公告。', '2026-07-06 21:29:53', '2026-07-06 21:29:53'),
('704cd884-b5d2-508e-a186-d32d7cea7d85', '79cff2d2-c43d-4022-9d79-f104e48b1d5b', 'The company''s ___ report provides a detailed summary of all activities from the past year.', '該公司的年度報告提供了過去一年所有活動的詳細摘要。', 'annual', 'monthly', 'special', 'global', '字根 ann- 來自拉丁語 annus，意為「年」。', '可以聯想 anniversary (週年紀念)，兩者都含有「年」的概念。', '2026-07-06 21:35:17', '2026-07-06 21:35:17'),
('7e806a97-e64d-541f-bdd1-1ebb4c720bc5', 'df3b25a9-fb2b-45dc-8e2e-bf5fb50ea736', 'Please ___ the phone.', '請接聽電話。', 'answer', 'clean', 'sing', 'dance', 'answer 在此作為動詞，表示接聽。', 'answer the phone 是一個常用的片語，表示接電話。', '2026-07-06 14:19:54', '2026-07-06 14:19:54'),
('d447f7d0-d140-5a52-a69e-2b3046980759', 'e3a4aef8-1a02-45d4-a01a-7e1bc70ddbcd', 'It became ___ to everyone that the team had not practiced enough for the competition.', '每個人都很明顯地看出，這支隊伍為了比賽練習得不夠。', 'apparent', 'absent', 'ancient', 'anxious', '字根 apparen- 源自拉丁語 apparere，意為「出現」(to appear)，因此引申為「顯而易見的」。', '想像一個東西「出現」(appear) 在你面前，你就會覺得它很「明顯」(apparent)。', '2026-07-06 22:51:26', '2026-07-06 22:51:26'),
('417694c1-7b3a-55a3-8fe0-b95536f2ea79', 'd1d897b7-a598-424a-bea4-da75f3e7d749', 'In the grammar textbook, the term ''___'' is often used as a shorthand for ''article''.', '在語法教科書中，''___'' 這個術語經常被用作 ''article'' (冠詞) 的縮寫。', 'art.', 'adj.', 'adv.', 'prep.', 'art. 是 article (冠詞) 的縮寫。', '記住 article 縮寫為 art.，這在語法標記中很常見。', '2026-07-07 00:21:18', '2026-07-07 00:21:18'),
('7512c02b-493e-563d-a434-a5bfa2596659', '3ec95093-60cd-4f79-a464-d499d7a6104a', 'The hungry tiger began to ___ the deer in the forest.', '那隻飢餓的老虎開始在森林中襲擊那隻鹿。', 'attack', 'protect', 'feed', 'help', 'attack 結合了表示朝向的字首與表示觸碰的字根，意為進攻。', '想像老虎對著獵物發動「攻擊」(attack) 的情景。', '2026-07-06 15:00:59', '2026-07-06 15:00:59'),
('591ad70f-2666-586e-b98b-30863eb0335d', '503bfce3-13aa-4f34-abf9-cab0bce512f9', 'I think I have seen that man ___.', '我想我以前見過那個人。', 'before', 'soon', 'always', 'lately', 'before 當副詞時，放在句末表示『以前』或『曾經』。', 'have seen... before → 以前看過', '2026-07-07 03:08:42', '2026-07-07 03:08:42'),
('782de7ba-731f-50a4-a13e-6142a2d99951', '287bf46d-3075-48c6-91ee-4767301120f6', 'The actors took a ___ to the audience to show their respect after the play.', '表演結束後，演員們向觀眾鞠躬以示尊重。', 'bow', 'photo', 'gift', 'step', 'bow 在此作為名詞，指「鞠躬」這個動作。', '想像演員在舞台上表演結束後，彎腰向觀眾致意的動作。', '2026-07-07 05:51:07', '2026-07-07 05:51:07'),
('67804227-6b00-57e4-8be0-c9fea013454d', '5d20b73d-7d29-498d-92b3-52636f5571d1', 'I''d like a ___ of soda, please.', '我想要一罐汽水，謝謝。', 'can', 'cup', 'bag', 'box', '指『罐頭』這個容器。', 'Can 就是罐頭的意思。', '2026-07-05 11:43:54', '2026-07-05 11:43:54'),
('cb46f033-cf27-565d-a47f-f517d31b994d', '10cfb375-7528-4dac-aa0b-12b3a23c445f', 'Don''t forget to cook ___ for your brother tonight.', '今晚別忘了要為你弟弟煮晚餐。', 'dinner', 'breakfast', 'lunch', 'bread', 'dinner → 晚餐 (名詞)', 'dinner 晚餐，晚餐要吃得營養。', '2026-07-07 04:35:02', '2026-07-07 04:35:02'),
('59b71194-38ae-5b1c-8c6e-e56f37ae17c1', '87f4c3a6-4121-46f4-b4f6-c98aecea1972', 'It is important to stay calm ___ the emergency.', '在緊急情況期間，保持冷靜是很重要的。', 'during', 'despite', 'towards', 'beyond', 'dur- 表示持續或耐久', 'dur 聯想 duration (期間) → during (在...期間)', '2026-07-05 07:49:45', '2026-07-05 07:49:45'),
('4ff0432b-19c6-56b2-bc66-ef92c05edd35', 'f01f0b26-4247-48a7-ad1d-d238994bb813', 'The gardener dug a hole in the ___ to plant a flower.', '園丁在土地上挖了一個洞來種花。', 'earth', 'water', 'sky', 'air', 'earth 除了指地球，在描述自然環境時也可以指「土地」或「土壤」。', '種花需要土地 → earth。', '2026-07-07 03:04:17', '2026-07-07 03:04:17'),
('bb156d45-e37c-5e29-8761-ad762722a3f5', 'c0de433b-25a4-49e3-8bc0-863275b4fae9', 'This is the best movie I have ___ seen.', '這是我曾經看過最好的電影。', 'ever', 'slowly', 'loudly', 'happily', 'ever 作為副詞，常用於最高級之後，用來強調「有史以來」。', '最高級 (the best) + ever → 「有史以來最...」', '2026-07-07 04:26:16', '2026-07-07 04:26:16'),
('773d2f94-6e22-587f-959e-54a3f5cd2209', 'e0bb2362-569d-4d00-ba8d-26e21f0d8ecd', 'Drinking water every morning is a healthy ___ .', '每天早上喝水是一個健康的習慣。', 'habit', 'hobby', 'dream', 'tool', 'habit 源自拉丁語 habere，意為「擁有」或「持有」，引申為擁有的行為模式。', '每天都要「哈」一下，做久了就變成 habit (習慣)。', '2026-07-08 06:51:07', '2026-07-08 06:51:07'),
('e6926c6d-6006-503c-ab7f-243c479782e1', '4c34c702-cad7-4c40-9cd1-d439687e72fb', 'It is very sunny today, so please wear a ___ to protect your head.', '今天陽光很強，所以請戴上一頂帽子來保護你的頭部。', 'hat', 'bag', 'shoe', 'sock', '名詞，指戴在頭上的衣物配件。', '想像在太陽下戴著 hat 遮陽。', '2026-07-08 07:00:49', '2026-07-08 07:00:49'),
('95377d2f-ab0b-5fda-b35a-3d163b18183d', 'c0215e23-91f1-4ae9-b39b-b68eff80cb98', 'The science teacher''s lecture was so ___ that we all wanted to learn more about the topic.', '科學老師的講座非常有趣，以至於我們都想了解更多關於這個主題的知識。', 'interesting', 'boring', 'difficult', 'noisy', '字首 inter- (在...之間), 字根 est (存在), 字尾 -ing (令人...的)', 'interest (興趣) + ing (令人...的) → interesting (有趣的)', '2026-07-05 05:46:37', '2026-07-05 05:46:37');
